661→export class RefCountedDisposable {
662→
663→	private _counter: number = 1;
664→
665→	constructor(
666→		private readonly _disposable: IDisposable,
667→	) { }
668→
669→	acquire() {
670→		this._counter++;
671→		return this;
672→	}
673→
674→	release() {
675→		if (--this._counter === 0) {
676→			this._disposable.dispose();
677→		}
678→		return this;
